import{_ as a,o as i,c as t,a2 as n}from"./chunks/framework.LN3EJxkW.js";const h=JSON.parse('{"title":"Write Lili Learning Notes","description":"Create, expand, audit, and update Chinese Markdown learning articles for the Lili software product engineer roadmap. Use for beginner, junior, or intermediate notes that must explain concepts deeply, verify current facts with primary web sources, include practical examples and useful visuals, remain maintainable in Obsidian/GitHub/VS Code, and avoid editorial commentary or unsupported claims.","frontmatter":{"name":"write-lili-learning-notes","description":"Create, expand, audit, and update Chinese Markdown learning articles for the Lili software product engineer roadmap. Use for beginner, junior, or intermediate notes that must explain concepts deeply, verify current facts with primary web sources, include practical examples and useful visuals, remain maintainable in Obsidian/GitHub/VS Code, and avoid editorial commentary or unsupported claims."},"headers":[],"relativePath":"skills/write-lili-learning-notes/SKILL.md","filePath":"skills/write-lili-learning-notes/SKILL.md","lastUpdated":1784250624000}'),r={name:"skills/write-lili-learning-notes/SKILL.md"};function o(l,e,s,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="write-lili-learning-notes" tabindex="-1">Write Lili Learning Notes <a class="header-anchor" href="#write-lili-learning-notes" aria-label="Permalink to &quot;Write Lili Learning Notes&quot;">​</a></h1><p>Produce a self-contained learning tutorial, not a summary card or research log.</p><h2 id="required-reading" tabindex="-1">Required reading <a class="header-anchor" href="#required-reading" aria-label="Permalink to &quot;Required reading&quot;">​</a></h2><p>Read <a href="./references/article-standard">references/article-standard.md</a> completely before writing or auditing any note. Read <a href="./references/visuals">references/visuals.md</a> when the topic has a process, hierarchy, state change, architecture, rendered interface, browser output, chart, or other relationship that benefits from a visual.</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><ol><li>Read the target roadmap item, existing article, adjacent notes, and index.</li><li>Define the article&#39;s exact knowledge boundary. Keep one coherent knowledge point per article; split only when the roadmap item contains independently learnable subjects.</li><li>Browse current primary sources. Prefer living standards, official documentation, specifications, original papers, authoritative public data, and source repositories. Use secondary material only to discover questions or improve organization.</li><li>Reduce every claim to its prerequisites and mechanism. Check definitions, defaults, units, inheritance, state transitions, failure conditions, compatibility, deprecation, and version-specific behavior.</li><li>Write or expand the article using the applicable template in <code>article-standard.md</code>. When expanding an existing short note, restructure it into one continuous teaching path. Remove or merge the old summary sections; do not append a second explanation and case after the old template.</li><li>Add examples that can be executed, inspected, calculated, or followed. Never invent output.</li><li>Add the smallest useful visual. For rendered UI or browser behavior, create a runnable example, render it in a real browser, inspect the DOM/state/errors, and save the resulting image in the repository.</li><li>Validate links, code fences, local assets, examples, article structure, and repository formatting. Run <code>scripts/validate_note.py</code> on every changed note.</li><li>Run <code>scripts/validate_code_blocks.py</code> with an explicit Node.js path when the notes contain JSON, JavaScript, or shell examples; compile TypeScript and other languages with their real toolchains when available.</li><li>When a directory or stage is complete, run <code>scripts/audit_corpus.py</code> on the whole set to detect short notes and repeated long prose across articles.</li><li>Update the direction index and global counts only when adding, deleting, or splitting articles.</li></ol><h2 id="hard-rules" tabindex="-1">Hard rules <a class="header-anchor" href="#hard-rules" aria-label="Permalink to &quot;Hard rules&quot;">​</a></h2><ul><li>Explain what the concept is, why it exists, how it works, how to use it, special behavior, failure modes, boundaries, verification, and related knowledge.</li><li>Keep one explanation path per concept. Repeated “brief version + expanded version”, duplicate cases, and appended template sections are incomplete even when the file passes length checks.</li><li>Expand named attributes, parameters, methods, states, metrics, rules, or variants individually when readers need them to use the concept.</li><li>State the actual rule directly. Do not include research-process narration, source-selection commentary, writing references, or remarks meant only for maintainers.</li><li>Do not add analogies, motivational filler, scene-setting prose, fake quotations, or unsupported absolutes.</li><li>Do not treat a framework, heuristic, convention, or vendor behavior as a universal law.</li><li>Separate standard requirements, implementation behavior, compatibility status, team conventions, and recommendations.</li><li>Put deterministic safety, authorization, validation, accounting, and business invariants in code or controlled systems, not in prompts or visual conventions.</li><li>Prefer semantic HTML, accessible interaction, secure defaults, explicit errors, and production-safe commands.</li><li>Never use screenshots as the only explanation. Pair each image with text, source code, or inspectable state.</li><li>Use ordinary relative Markdown links for repository navigation. Do not use Obsidian-only <code>[[wiki links]]</code>; standard Markdown works in GitHub, Obsidian, and VS Code.</li><li>Keep citations in <code>## 来源</code>. Do not insert citations as filler after every sentence.</li></ul><h2 id="level-control" tabindex="-1">Level control <a class="header-anchor" href="#level-control" aria-label="Permalink to &quot;Level control&quot;">​</a></h2><ul><li>Beginner and junior notes must build vocabulary from zero, enumerate the practical surface, show small complete examples, explain common mistakes, and include exercises with completion criteria.</li><li>Intermediate notes must assume the prerequisite notes, deepen mechanisms, include at least two substantial applications, compare alternatives, show debugging or validation, cover operational and production boundaries, and end with an integration exercise or project acceptance criteria.</li></ul><h2 id="completion-gate" tabindex="-1">Completion gate <a class="header-anchor" href="#completion-gate" aria-label="Permalink to &quot;Completion gate&quot;">​</a></h2><p>Do not mark an article complete until:</p><ul><li>Every heading and example has substantive content.</li><li>Beginner/junior notes normally reach at least 120 lines and 8 KB of real content; intermediate notes normally reach at least 200 lines and 12 KB. Falling below either floor requires expansion, not template padding.</li><li>A worked case includes concrete input/evidence, step-by-step processing, output, verification, and at least one failure branch.</li><li>Every factual statement that can change has been checked against a current primary source.</li><li>Every important term introduced by the roadmap item is defined and operationalized.</li><li>Code and commands are syntactically valid and safe in their stated context.</li><li>Complete HTML examples pass an HTML5 conformance checker; other executable examples pass the relevant parser, compiler, test, or dry-run check when available.</li><li>Visuals render in both GitHub-compatible Markdown and Obsidian, or have a repository image fallback.</li><li>The article contains no editorial/process commentary forbidden by the standard.</li><li>The validator and <code>git diff --check</code> pass.</li></ul>',13)])])}const m=a(r,[["render",o]]);export{h as __pageData,m as default};
